PeatErrorException _uniffiLiftPeatErrorException(Uint8List bytes) {
  final PeatError value = _uniffiDecodePeatError(bytes);
  if (value is PeatErrorEncodingError) {
    return PeatErrorExceptionEncodingError(
      msg: value.msg,
    );
  }
  if (value is PeatErrorInvalidInput) {
    return PeatErrorExceptionInvalidInput(
      msg: value.msg,
    );
  }
  if (value is PeatErrorStorageError) {
    return PeatErrorExceptionStorageError(
      msg: value.msg,
    );
  }
  if (value is PeatErrorConnectionError) {
    return PeatErrorExceptionConnectionError(
      msg: value.msg,
    );
  }
  if (value is PeatErrorSyncError) {
    return PeatErrorExceptionSyncError(
      msg: value.msg,
    );
  }
  throw StateError('Unknown PeatError error variant while lifting exception: $value');
}

